using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelTrainer
{
    private readonly MLContext _mlContext;
    private readonly ILogger<TicketModelTrainer> _logger;

    public TicketModelTrainer(ILogger<TicketModelTrainer> logger)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
    }

    public void TrainAndSave(string dataPath, string modelPath)
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue(
                "PredictedLabel", "PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(
            predictions, labelColumnName: "Label");

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("Log Loss Reduction: {LogLossReduction:F4}", metrics.LogLossReduction);
        _logger.LogInformation("Confusion Matrix:\n{Matrix}", metrics.ConfusionMatrix.GetFormattedConfusionTable());

        _mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);
        _logger.LogInformation("Model saved to {Path}", modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;

    public TicketClassifierController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("predict")]
    public ActionResult<PredictionResult> Predict([FromBody] TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);
        var labels = new[] { "Billing", "General", "Technical" };
        var confidences = labels.Zip(prediction.Score)
            .ToDictionary(x => x.First, x => Math.Round(x.Second, 4));

        return Ok(new PredictionResult
        {
            Category = prediction.Category,
            Confidence = confidences
        });
    }
}

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class PredictionResult
{
    public string Category { get; set; } = string.Empty;
    public Dictionary<string, double> Confidence { get; set; } = new();
}

