            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);
        var labels = new[] { "Billing", "General", "Technical" };
        var confidences = labels.Zip(prediction.Score)
            .ToDictionary(x => x.First, x => Math.Round(x.Second, 4));

        return Ok(new PredictionResult
        {
            Category = prediction.Category,
            Confidence = confidences
        });
    }
}

